script:
frappe.listview_settings["Purchase Order"] = {
    onload(listview) {

        let preview_dialog;
        let po_names = [];
        let current_index = 0;

        function get_dialog() {
            if (!preview_dialog) {
                preview_dialog = new frappe.ui.Dialog({
                    title: "Purchase Order Preview",
                    size: "large",
                    fields: [
                        { fieldtype: "HTML", fieldname: "preview_html" }
                    ]
                });
            }
            return preview_dialog;
        }

        async function load_preview(name) {

            if (!name) {
                frappe.msgprint("Unable to detect Purchase Order ID");
                return;
            }

            const dialog = get_dialog();
            dialog.show();

            const wrapper = dialog.fields_dict.preview_html.$wrapper;
            wrapper.html("<p>Loading...</p>");

            try {

                const doc = await frappe.db.get_doc("Purchase Order", name);

                const card_style = `
                    border:1px solid #ddd;
                    border-radius:0.5rem;
                    box-shadow:0 2px 6px rgba(0,0,0,0.1);
                    padding:1rem;
                    background:#fff;
                `;

                let status_bg = "gray";

                if (doc.status === "To Receive and Bill") status_bg = "orange";
                else if (doc.status === "Completed") status_bg = "green";
                else if (doc.status === "Draft") status_bg = "blue";
                else if (doc.status === "Cancelled") status_bg = "red";

                const po_summary = `
<div class="d-flex flex-wrap" style="${card_style}; margin-bottom:1rem;">

<div class="flex-fill" style="min-width:250px;">
<h5>Purchase Order Details</h5>

<p><b>PO No:</b> ${doc.name}</p>
<p><b>Supplier:</b> ${doc.supplier}</p>
<p><b>Date:</b> ${doc.transaction_date}</p>

<p><b>Status:</b>
<span style="
background:${status_bg};
color:white;
padding:3px 8px;
border-radius:4px;
font-weight:bold;">
${doc.status}
</span>
</p>

</div>

<div class="flex-fill" style="min-width:250px;">
<h5>Totals</h5>

<div class="d-flex justify-content-between">
<span>Total</span>
<span>${doc.total.toLocaleString('en-IN',{style:'currency',currency:'INR'})}</span>
</div>

<div class="d-flex justify-content-between">
<span>Taxes</span>
<span>${doc.total_taxes_and_charges.toLocaleString('en-IN',{style:'currency',currency:'INR'})}</span>
</div>

<div class="d-flex justify-content-between" style="font-weight:bold;background:#f7f7f7;padding:4px;border-radius:4px;">
<span>Grand Total</span>
<span>${doc.grand_total.toLocaleString('en-IN',{style:'currency',currency:'INR'})}</span>
</div>

</div>

</div>
`;

                const items_html = (doc.items || []).map(i => `
<tr style="text-align:center;">
<td>${i.item_code}</td>
<td>${i.qty}</td>
<td>${i.uom || "-"}</td>
<td>${i.rate.toLocaleString('en-IN',{style:'currency',currency:'INR'})}</td>
<td>${i.amount.toLocaleString('en-IN',{style:'currency',currency:'INR'})}</td>
</tr>
`).join("");

                const items_card = `
<div style="${card_style}; margin-bottom:1rem;">

<h5>Items</h5>

<table class="table table-sm table-bordered table-striped">
<thead>

<tr>
<th>Item</th>
<th>Qty</th>
<th>UOM</th>
<th>Rate</th>
<th>Amount</th>
</tr>

</thead>

<tbody>
${items_html}
</tbody>

</table>

</div>
`;

                const content = `${po_summary}${items_card}`;

                wrapper.html(`

<div style="position:relative;padding-bottom:60px;">

${content}

<div class="mt-3">
<a href="/app/purchase-order/${doc.name}" class="btn btn-primary btn-sm">
Open Full Purchase Order
</a>
</div>

<div style="position:absolute;bottom:15px;right:15px;display:flex;gap:8px;">

<span id="prev-arrow"
style="cursor:pointer;background:#007bff;color:white;padding:6px 10px;border-radius:4px;">
${frappe.utils.icon("arrow-left","sm")} Prev
</span>

<span id="arrow-badge"
style="background:#28a745;color:white;padding:4px 10px;border-radius:4px;font-weight:bold;">
${current_index + 1} / ${po_names.length}
</span>

<span id="next-arrow"
style="cursor:pointer;background:#007bff;color:white;padding:6px 10px;border-radius:4px;">
Next ${frappe.utils.icon("arrow-right","sm")}
</span>

</div>

</div>

`);

                const prevArrow = wrapper.find("#prev-arrow");
                const nextArrow = wrapper.find("#next-arrow");
                const badge = wrapper.find("#arrow-badge");

                function update_badge() {
                    badge.text(`${current_index + 1} / ${po_names.length}`);
                    prevArrow.css("opacity", current_index === 0 ? 0.5 : 1);
                    nextArrow.css("opacity", current_index === po_names.length - 1 ? 0.5 : 1);
                }

                prevArrow.on("click", async () => {
                    if (current_index > 0) {
                        current_index--;
                        await load_preview(po_names[current_index]);
                        update_badge();
                    }
                });

                nextArrow.on("click", async () => {
                    if (current_index < po_names.length - 1) {
                        current_index++;
                        await load_preview(po_names[current_index]);
                        update_badge();
                    }
                });

                update_badge();

            } catch (err) {
                frappe.msgprint("Error loading preview: " + err.message);
                console.error(err);
            }

        }

        listview.after_render = function () {

            po_names = [];

            listview.$result.find(".list-row").each(function () {

                const title = $(this).find('[title^="ID:"]').attr("title");

                if (title && title.includes("ID:")) {
                    po_names.push(title.replace("ID: ", "").trim());
                }

                const $row = $(this);

                if ($row.find(".quick-preview-btn").length) return;

                const eye = `
<span class="quick-preview-btn mx-2"
title="Quick Preview"
style="cursor:pointer; width:11px">
${frappe.utils.icon("eye","sm")}
</span>`;

                $row.find(".list-row-activity").prepend(eye);

            });

        };

        listview.$result.on("click", ".quick-preview-btn", function (e) {

            e.stopPropagation();

            const title = $(this).closest(".list-row").find('[title^="ID:"]').attr("title");

            if (!title) return;

            const name = title.replace("ID: ", "").trim();

            current_index = po_names.indexOf(name);

            load_preview(name);

        });

    }
};
